public class Solution {
    public ListNode MergeTwoLists(ListNode list1, ListNode list2) {

        ListNode currFirstList = list1;
        ListNode currSecondList = list2;
        ListNode dummyNode = new ListNode(0);
        ListNode curr = dummyNode;

        while(currFirstList!=null && currSecondList!=null){

            if(currFirstList.val < currSecondList.val){
                curr.next = currFirstList;
                currFirstList = currFirstList.next;
                curr = curr.next;
            }
            else{
                curr.next = currSecondList;
                currSecondList = currSecondList.next;
                curr = curr.next;
            }            
        }

         curr.next = currFirstList ?? currSecondList;
         return dummyNode.next;

    }
}

