public class Solution {
    public int Search(int[] nums, int target) {

        int indMin=FindIndOfMin(nums);

        if(target==nums[indMin]){
            return indMin;
        }


        bool leftSearch = target>nums[nums.Length-1];

        int l =-1;
        int r=-1;

        if(leftSearch){
            l=0;
            r=indMin-1;
        }else{
            l = indMin + 1;
            if (l >= nums.Length) return -1;  
            r = nums.Length - 1;
        }

        while(l<r){
            int mid=(l+r)/2;
            if(target==nums[mid]){
                return mid;
            }
            else if(target>nums[mid]){
                l=mid+1;
            }
            else{
                r=mid-1;
            }
        }

        if(target==nums[l]){
            return l;
        }

        return -1;

    }

    public int FindIndOfMin(int[] nums) {

        // Your solution here
        int l=0;
        int r=nums.Length-1;

        while(l<r){
            int mid=(l+r)/2;
            if(nums[mid]>nums[r]){
                l=mid+1;
            }
            else{
                r=mid;
            }
        }

        return l;
    }
}

