    public static int[] GetProductToRight(int[] nums){

        int[] rightProdArr = new int[nums.Length];

        rightProdArr[nums.Length-1]=1;

        for (int i = nums.Length-2; i >= 0; i--)
        {
            rightProdArr[i]=rightProdArr[i+1]*nums[i+1];
        }

        return rightProdArr;
    }
}

