public class Solution
 {
     public IList<IList<int>> ThreeSum(int[] nums)
     {
         IList<IList<int>> result = new List<IList<int>>();

         Array.Sort(nums);

         int len = nums.Length;
         int outIdx = 0;

         while (outIdx < len - 2)
         {
             // skip duplicate outIdx
             if (outIdx > 0 && nums[outIdx] == nums[outIdx - 1])
             {
                 outIdx++;
                 continue;
             }

             int l = outIdx + 1;
             int r = len - 1;

             while (l < r)
             {
                 int target = -nums[outIdx];
                 int currSum = nums[l] + nums[r];

                 if (target == currSum)
                 {
                     result.Add(new List<int> { nums[outIdx], nums[l], nums[r] });
                     l++;
                     r--;
                     // skip duplicate l
                     while (l < r && nums[l] == nums[l - 1]) l++;
                     // skip duplicate r
                     while (l < r && nums[r] == nums[r + 1]) r--;
                 }
                 else if (currSum < target)
                 {
                     l++;
                 }
                 else
                 {
                     r--;
                 }
             }

             outIdx++;
         }

         return result;
     }
 }

