public class Solution {
    public bool Exist(char[][] board, string word) {
        int rows = board.Length;
        int cols = board[0].Length;
        bool[,] used = new bool[rows,cols];

        for(int i =0;i< rows;i++){
            for(int j =0;j<cols; j++){
                 if (backtrack(board, word, used, i, j, 0)){
                    return true;
                 }
            }
        }
        return false;
    }

    private bool backtrack(char[][] board, string word, bool[,] used,  int r, int c, int index){
        if(r < 0 || r >= board.Length || c < 0 || c >= board[0].Length){
            return false;
        }

        if(used[r,c]){
            return false; 
        }

        if(word[index]!=board[r][c]){
            return false;
        }

        if(index == word.Length-1){
            return true;
        }

        used[r,c]=true;

        bool found = backtrack(board, word, used, r-1, c, index+1)  || 
        backtrack(board, word, used, r+1, c, index+1) ||  
        backtrack(board, word, used, r, c-1, index+1) ||  
        backtrack(board, word, used, r, c+1, index+1) ;

        used[r, c] = false;
        return found;
    }
}

