public class Solution {
      public bool CanFinish(int numCourses, int[][] prerequisites) {
          // Step 1: build adjacency list — course → list of its prerequisites
          Dictionary<int, List<int>> dict = new Dictionary<int, List<int>>();

          for (int r = 0; r < prerequisites.Length; r++) {
              int courseToBeTaken = prerequisites[r][0];
              int preReq = prerequisites[r][1];

              if (dict.ContainsKey(courseToBeTaken)) {
                  dict[courseToBeTaken].Add(preReq);
              } else {
                  dict[courseToBeTaken] = [preReq];
              }
          }

          // Step 2: check every course for a cycle
          for (int i = 0; i < numCourses; i++) {
              if (HasCycle(i, new HashSet<int>(), dict)) return false;
          }

          return true;
      }

      private bool HasCycle(int course, HashSet<int> seen, Dictionary<int, List<int>> dict) {
          // already visited in this chain → cycle found
          if (seen.Contains(course)) return true;

          // no prerequisites → no cycle possible from here
          if (!dict.ContainsKey(course)) return false;

          // mark this course as visited in the current chain
          seen.Add(course);

          // follow every prerequisite recursively
          foreach (int prereq in dict[course]) {
              if (HasCycle(prereq, seen, dict)) return true;
          }

          // done with this path — unmark so other paths can use this course
          seen.Remove(course);
          return false;
      }
  }

